'use client';

import React, { useState, useEffect, Suspense } from 'react';
import { useSearchParams } from 'next/navigation';
import SettingsPanel from '@/components/SettingsPanel';
import FileProcessor from '@/components/FileProcessor';
import { useLanguage } from '@/lib/context/LanguageContext';
import { useFileBatchProcessor } from '@/lib/hooks/useFileBatchProcessor';
import { useInactivityPurge } from '@/lib/hooks/useInactivityPurge';
import { ShieldCheckIcon, UnlockIcon } from '@/components/common/Icons';

interface SelectedFile {
  file: File;
  id: string;
}

function CryptPageContent() {
  const { t } = useLanguage();
  const searchParams = useSearchParams();
  const mode = (searchParams.get('view') === 'decrypt') ? 'decrypt' : 'encrypt';

  // Elevated state from FileProcessor
  const [files, setFiles] = useState<SelectedFile[]>([]);

  // Local Settings State
  const [password, setPassword] = useState('');
  const [batchMode, setBatchMode] = useState(false);
  const [outputSuffix, setOutputSuffix] = useState(mode === 'encrypt' ? '.enc' : '_decrypted');

  // Reset suffix when mode changes (optional, but requested behavior implies defaults)
  useEffect(() => {
    setOutputSuffix(mode === 'encrypt' ? '.enc' : '_decrypted');
  }, [mode]);

  // Business Logic Hooks
  const { 
    isProcessing, 
    processFiles, 
    clearLogs, 
    addLog,
    stats
  } = useFileBatchProcessor({ 
    password, 
    outputSuffix 
  });

  // Security Hook
  useInactivityPurge({
    password,
    onPurge: (messageKey) => {
      setPassword('');
      addLog('error', `logs.${messageKey}`);
    }
  });

  const handleProcess = () => {
    processFiles(files.map(f => f.file), mode);
    if (!batchMode) setFiles([]);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '24px', height: '100%' }}>
      <header className="station-panel-header" style={{ padding: '0 0 20px 0' }}>
        <div className="flex-col" style={{ gap: '4px' }}>
          <h2 className="station-title-main" style={{ margin: 0 }}>
            {mode === 'encrypt' ? t('crypt.shield_vault').toUpperCase() : t('crypt.open_key').toUpperCase()}
          </h2>
          <div className="flex-row" style={{ alignItems: 'center', gap: '12px' }}>
             <span style={{ opacity: 0.5, fontSize: '0.75rem', fontWeight: 700 }}>ENGINE: AES-GCM 256</span>
             <span className="station-badge station-badge-blue">SECURE_CONTEXT</span>
             <span className={`station-badge ${password ? 'station-badge-green' : 'station-badge-orange'}`}>
                {password ? 'VAULT_OPEN' : 'VAULT_LOCKED'}
             </span>
          </div>
        </div>
      </header>


      <div style={{ display: 'flex', flexDirection: 'column', gap: '64px', flex: 1, minHeight: 0 }}>
        <section style={{ display: 'flex', flexDirection: 'column' }}>
          <FileProcessor
            files={files}
            setFiles={setFiles}
            onClear={(n) => addLog('error', 'logs.list_cleared', undefined, { n })}
            onSort={() => addLog('info', 'logs.sort_applied')}
            isProcessing={isProcessing}
            stats={stats}
            hideEmpty={true}
          />
        </section>

        {files.length === 0 && (
          <div className="station-empty-state" style={{ marginTop: '40px' }}>
             <ShieldCheckIcon size={64} style={{ marginBottom: '16px' }} />
             <span className="station-shimmer-text">CRYPT_VAULT_AWAITING_INPUT</span>
          </div>
        )}

        {files.length > 0 && (
          <section style={{ display: 'flex', flexDirection: 'column' }}>
            <SettingsPanel
              mode={mode}
              password={password}
              setPassword={setPassword}
              batchMode={batchMode}
              setBatchMode={setBatchMode}
              outputSuffix={outputSuffix}
              setOutputSuffix={setOutputSuffix}
              onProcess={handleProcess}
              isProcessing={isProcessing}
              canProcess={files.length > 0 && password.trim().length > 0}
            />
          </section>
        )}
      </div>

      {/* Sello de Integridad (Era 5) */}
      <div className="station-integrity-badge" style={{ position: 'fixed', bottom: '24px', right: '24px' }}>
         <div className="integrity-dot" />
         <ShieldCheckIcon size={14} />
         <span>AES-GCM 256 INDUSTRIAL</span>
      </div>
    </div>
  );
}

export default function Home() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <CryptPageContent />
    </Suspense>
  );
}

'use client';

import React, { useState, useEffect, Suspense } from 'react';
import { useLiveQuery } from 'dexie-react-hooks';
import { useSearchParams, useRouter } from 'next/navigation';
import { useLanguage } from '@/lib/context/LanguageContext';
import { db } from '@/lib/db/db';
import { EtlPreset } from '@/lib/types/etl.types';
import { normalizeEtlPreset } from '@/lib/utils/etl-importer';
import { EtlSidebar } from '@/components/Etl/EtlSidebar';
import { EtlDesigner } from '@/components/Etl/EtlDesigner';
import { CogIcon, MapIcon, PlayIcon } from '@/components/common/Icons';
import EtlSettingsModal from '@/components/Etl/EtlSettingsModal';
import { EtlGlobalSettings } from '@/lib/types/etl.types';
import EtlRunner from '@/components/Etl/EtlRunner';

const STORAGE_KEY = 'abdfn_etl_global_settings';

const DEFAULT_SETTINGS: EtlGlobalSettings = {
  defaultPath: 'C:\\ABD\\ETL',
  language: 'es',
  defaultEncoding: 'utf-8',
  defaultChunkSize: 900000
};

function EtlPageContent() {
  const { t } = useLanguage();
  const searchParams = useSearchParams();
  const router = useRouter();

  const activeTab = (searchParams.get('view') === 'executor' || searchParams.get('view') === 'runner') ? 'runner' : 'designer';
  const idParam = searchParams.get('id');

  const [selectedPreset, setSelectedPreset] = useState<EtlPreset | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [etlSettings, setEtlSettings] = useState<EtlGlobalSettings>(DEFAULT_SETTINGS);

  // Persistence (Dexie)
  const presets = useLiveQuery(() => db.presets_v6.toArray()) || [];

  // Load Global Settings
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setEtlSettings(JSON.parse(saved));
      } catch (e) {
        console.error('Failed to parse ETL settings', e);
      }
    }
  }, []);

  // Sync selectedPreset with URL ID param
  useEffect(() => {
    if (idParam && presets.length > 0) {
      if (selectedPreset?.id !== idParam) {
        const p = presets.find(x => x.id === idParam);
        if (p) setSelectedPreset(p);
      }
    }
  }, [idParam, presets, selectedPreset?.id]);

  const saveGlobalSettings = (newSettings: EtlGlobalSettings) => {
    setEtlSettings(newSettings);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newSettings));
  };

  const handleNew = async () => {
    const newPreset: EtlPreset = {
      name: 'NEW_PRESET_' + (presets.length + 1),
      version: '1.0',
      description: '',
      chunkSize: etlSettings.defaultChunkSize,
      encoding: etlSettings.defaultEncoding,
      recordTypeStart: 0,
      recordTypeLen: 0,
      defaultRecordType: '',
      headerTypeId: '',
      recordTypes: [],
      isActive: true,
      createdAt: Date.now(),
      updatedAt: Date.now()
    };
    const id = await db.presets_v6.add(newPreset);
    router.push(`/etl?view=${activeTab}&id=${id}`);
  };

  const handleSave = async () => {
    if (!selectedPreset || !selectedPreset.id) return;
    await db.presets_v6.put(selectedPreset);
  };

  const handleDelete = async (id: string) => {
    if (confirm(t('common.confirm_delete') || 'DELETE?')) {
      await db.presets_v6.delete(id);
      if (selectedPreset?.id === id) {
        setSelectedPreset(null);
        router.push(`/etl?view=${activeTab}`);
      }
    }
  };

  const handleExport = (preset: EtlPreset) => {
    const data = JSON.stringify(preset, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `etl_preset_${preset.name.replace(/\s+/g, '_')}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleExportAll = async () => {
    const data = JSON.stringify(presets, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `abdfn_etl_presets_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleImport = async () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';
    input.onchange = async (e: any) => {
      const file = e.target.files[0];
      if (file) {
        try {
          const text = await file.text();
          const rawData = JSON.parse(text);
          const normalized = normalizeEtlPreset(rawData);
          const id = await db.presets_v6.add(normalized);
          router.push(`/etl?view=${activeTab}&id=${id}`);
        } catch (err) {
          console.error('FAILED_TO_IMPORT_Preset', err);
        }
      }
    };
    input.click();
  };

  const handleSelectPreset = (p: EtlPreset) => {
    setSelectedPreset(p);
    router.push(`/etl?view=${activeTab}&id=${p.id}`);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '24px', height: '100%' }}>
      <header className="module-title" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px', fontSize: '1.2rem', fontWeight: 800 }}>
          {activeTab === 'designer' ? (
            <>
              <MapIcon size={24} style={{ opacity: 0.6 }} />
              {t('etl.app_designer')}
            </>
          ) : (
            <>
              <PlayIcon size={24} style={{ opacity: 0.6 }} />
              {t('etl.app_executor')}
            </>
          )}
        </div>
        <button 
          className="station-btn"
          onClick={() => setIsSettingsOpen(true)}
          title={t('etl.preferences')}
          style={{ padding: '4px', boxShadow: 'none', background: 'transparent', border: 'none' }}
        >
          <CogIcon size={20} />
        </button>
      </header>

      <EtlSettingsModal 
        isOpen={isSettingsOpen}
        initialSettings={etlSettings}
        onClose={() => setIsSettingsOpen(false)}
        onSave={saveGlobalSettings}
      />

      <div style={{ display: 'flex', flexDirection: 'column', gap: '64px', flex: 1, minHeight: 0 }}>
        <section style={{ display: 'flex', flexDirection: 'column' }}>
          <EtlSidebar 
            presets={presets}
            activePresetId={selectedPreset?.id}
            onSelect={handleSelectPreset}
            onDelete={handleDelete}
            onExport={handleExport}
            onNew={handleNew}
            onImport={handleImport}
            onExportAll={handleExportAll}
          />
        </section>

        {selectedPreset ? (
          <section style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            <div style={{ flex: 1, minHeight: 0 }}>
              {activeTab === 'designer' ? (
                <EtlDesigner 
                  preset={selectedPreset} 
                  onUpdate={setSelectedPreset} 
                  onSave={handleSave}
                />
              ) : (
                <EtlRunner 
                  presets={presets}
                  selectedPreset={selectedPreset}
                  onSelectPreset={handleSelectPreset}
                />
              )}
            </div>
          </section>
        ) : (
          <div className="station-empty-state" style={{ flex: 1 }}>
             <MapIcon size={64} style={{ marginBottom: '16px' }} />
             <span className="station-shimmer-text">{t('etl.designer_standby').toUpperCase()}</span>
          </div>
        )}
      </div>
    </div>
  );
}

export default function EtlPage() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <EtlPageContent />
    </Suspense>
  );
}

'use client';

import React, { Suspense } from 'react';
import { useSearchParams } from 'next/navigation';
import { useLanguage } from '@/lib/context/LanguageContext';
import LetterStation from '@/components/LetterStation/LetterStation';
import TemplateEditor from '@/components/LetterStation/TemplateEditor';
import MappingMatrix from '@/components/LetterStation/MappingMatrix';
import LetterPresetEditor from '@/components/LetterStation/LetterPresetEditor';
import AuditStation from '@/components/AuditStation/AuditStation';
import { FileTextIcon, MapIcon, PlayIcon, ShieldCheckIcon, CogIcon } from '@/components/common/Icons';

function LetterPageContent() {
  const { t } = useLanguage();
  const searchParams = useSearchParams();
  const view = searchParams.get('view') || 'templates';

  const renderView = () => {
    switch (view) {
      case 'mapping':
        return <MappingMatrix />;
      case 'config':
        return <LetterPresetEditor />;
      case 'generation':
        return <LetterStation />; // mapping is now a separate view
      case 'audit':
        return <AuditStation />;
      case 'templates':
      default:
        return <TemplateEditor />;
    }
  };

  const getHeaderInfo = () => {
    switch (view) {
      case 'mapping':
        return { title: t('shell.letter_mapping'), icon: <MapIcon size={28} style={{ opacity: 0.6 }} /> };
      case 'config':
        return { title: t('shell.letter_config'), icon: <CogIcon size={28} style={{ opacity: 0.6 }} /> };
      case 'generation':
        return { title: t('shell.letter_generation'), icon: <PlayIcon size={28} style={{ opacity: 0.6 }} /> };
      case 'audit':
        return { title: t('shell.letter_audit'), icon: <ShieldCheckIcon size={28} style={{ opacity: 0.6 }} /> };
      case 'templates':
      default:
        return { title: t('shell.letter_templates'), icon: <FileTextIcon size={28} style={{ opacity: 0.6 }} /> };
    }
  };

  const { title, icon } = getHeaderInfo();

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '24px', height: '100%' }}>
      <header className="module-title" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px', fontSize: '1.2rem', fontWeight: 800 }}>
          {icon}
          {title}
        </div>
      </header>

      <section className="module-grid" style={{ flex: 1, minHeight: 0 }}>
        <div className="module-col-main" style={{ gridColumn: 'span 12' }}>
          {renderView()}
        </div>
      </section>
    </div>
  );
}

export default function LetterPage() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <LetterPageContent />
    </Suspense>
  );
}

