'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';

interface IndustrialVirtualTableProps<T> {
  items: T[];
  totalItems: number;
  itemHeight: number;
  containerHeight: number;
  renderRow: (item: T, index: number, style: React.CSSProperties) => React.ReactNode;
  onRangeChange?: (startIndex: number, endIndex: number) => void;
  className?: string;
  header?: React.ReactNode;
}

export function IndustrialVirtualTable<T>({
  items,
  totalItems,
  itemHeight,
  containerHeight,
  renderRow,
  onRangeChange,
  className,
  header
}: IndustrialVirtualTableProps<T>) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scrollTop, setScrollTop] = useState(0);

  const buffer = 5; // Filas de margen para suavizar el scroll

  const startIndex = Math.max(0, Math.floor(scrollTop / itemHeight) - buffer);
  const endIndex = Math.min(totalItems - 1, Math.floor((scrollTop + containerHeight) / itemHeight) + buffer);

  useEffect(() => {
    if (onRangeChange) {
      onRangeChange(startIndex + 1, endIndex + 1); // 1-based para GAWEB
    }
  }, [startIndex, endIndex, onRangeChange]);

  const handleScroll = useCallback((e: React.UIEvent<HTMLDivElement>) => {
    setScrollTop(e.currentTarget.scrollTop);
  }, []);

  const totalHeight = totalItems * itemHeight;

  return (
    <div className={`industrial-virtual-table ${className || ''}`} style={{ display: 'flex', flexDirection: 'column', height: '100%', overflow: 'hidden' }}>
      {header && <div className="virtual-table-header">{header}</div>}

      <div 
        ref={containerRef}
        onScroll={handleScroll}
        style={{ 
          flex: 1, 
          overflowY: 'auto', 
          position: 'relative',
          background: 'rgba(0,0,0,0.1)',
          border: '1px solid var(--border-color)'
        }}
      >
        {/* Espaciador para el scroll real */}
        <div style={{ height: `${totalHeight}px`, width: '100%', pointerEvents: 'none' }} />

        {/* Contenedor de filas visibles */}
        <div style={{ 
          position: 'absolute', 
          top: 0, 
          left: 0, 
          width: '100%', 
          transform: `translateY(${startIndex * itemHeight}px)` 
        }}>
          {items.map((item, i) => {
            const globalIndex = startIndex + i;
            if (globalIndex > endIndex) return null;

            return renderRow(item, globalIndex, {
              height: `${itemHeight}px`,
              display: 'flex',
              alignItems: 'center'
            });
          })}
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import jsPDF from 'jspdf';

interface RendererHostProps {
  onReady: (engine: any) => void;
}

/**
 * RendererHost
 * Componente asíncrono que carga los motores de renderizado de alta fidelidad.
 * Cumplimiento: Era 5 (Industrial Design)
 */
export const RendererHost: React.FC<RendererHostProps> = ({ onReady }) => {
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    const loadScripts = async () => {
      if ((window as any).docx) {
        setIsLoaded(true);
        return;
      }

      // 1. Carga de docx-preview (Vendorizado)
      const docxScript = document.createElement('script');
      docxScript.src = '/vendor/docx-preview.js';
      docxScript.async = true;

      // 2. Carga de html2canvas (Vendorizado)
      const canvasScript = document.createElement('script');
      canvasScript.src = '/vendor/html2canvas.min.js';
      canvasScript.async = true;

      document.body.appendChild(docxScript);
      document.body.appendChild(canvasScript);

      let attempts = 0;
      const check = setInterval(() => {
        attempts++;
        if ((window as any).docx && (window as any).html2canvas) {
          clearInterval(check);
          setIsLoaded(true);
          onReady(createEngine());
        }
        if (attempts > 50) {
          clearInterval(check);
          console.error('FAILED_TO_LOAD_HIGH_FIDELITY_ENGINES');
        }
      }, 200);
    };

    loadScripts();
  }, [onReady]);

  const renderQueue = React.useRef<Promise<any>>(Promise.resolve());

  const createEngine = () => ({
    renderToPdf: async (blob: Blob, filename: string): Promise<Blob> => {
      return new Promise((resolve, reject) => {
        renderQueue.current = renderQueue.current.then(async () => {
          try {
            const { pdf } = await renderAndProcess(blob, filename);
            resolve(pdf.output('blob'));
          } catch (err) {
            reject(err);
          }
        });
      });
    },
    captureFingerprint: async (blob: Blob, filename: string): Promise<string> => {
      return new Promise((resolve, reject) => {
        renderQueue.current = renderQueue.current.then(async () => {
          try {
            const { canvas } = await renderAndProcess(blob, filename);
            const { generateCanvasFingerprint } = await import('@/lib/logic/golden-tests.logic');
            resolve(await generateCanvasFingerprint(canvas));
          } catch (err) {
            reject(err);
          }
        });
      });
    }
  });

  const renderAndProcess = async (blob: Blob, filename: string) => {
      const isDocx = filename.toLowerCase().endsWith('.docx');
      const container = document.createElement(isDocx ? 'div' : 'iframe') as any;
      container.style.position = 'fixed';
      container.style.left = '0';
      container.style.top = '0';
      container.style.width = '800px'; 
      container.style.height = 'auto';
      container.style.overflow = 'visible'; 
      container.style.background = 'white';
      container.style.zIndex = '-9999';
      container.style.pointerEvents = 'none';
      container.id = `renderer_target_${Date.now()}`;

      document.body.appendChild(container);

      try {
        if (isDocx) {
          await (window as any).docx.renderAsync(blob, container, null, {
            className: "docx-high-fidelity",
            inWrapper: false,
            ignoreHeight: false,
            ignoreWidth: false,
            debug: false
          });
        } else {
          const htmlContent = await blob.text();
          const doc = container.contentWindow.document;
          doc.open();
          doc.write(`<!DOCTYPE html><html><head><style>body { background: white; margin: 0; padding: 40px; font-family: sans-serif; width: 800px; } * { color: black !important; }</style></head><body>${htmlContent}</body></html>`);
          doc.close();
        }

        await new Promise(r => requestAnimationFrame(() => requestAnimationFrame(r)));
        await new Promise(r => setTimeout(r, 1000));

        const target = isDocx ? container : container.contentWindow.document.body;
        const canvas = await (window as any).html2canvas(target, {
          scale: 2,
          useCORS: true,
          backgroundColor: '#ffffff',
          width: 800
        });

        const imgData = canvas.toDataURL('image/jpeg', 0.95);
        const pdf = new jsPDF('p', 'pt', 'a4');
        const pageWidth = pdf.internal.pageSize.getWidth();
        const pageHeight = pdf.internal.pageSize.getHeight();
        const imgWidth = pageWidth;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;

        let heightLeft = imgHeight;
        let position = 0;
        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight, undefined, 'FAST');
        heightLeft -= pageHeight;
        while (heightLeft > 0) {
          position = heightLeft - imgHeight;
          pdf.addPage();
          pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight, undefined, 'FAST');
          heightLeft -= pageHeight;
        }

        return { pdf, canvas };
      } finally {
        if (container.parentNode) document.body.removeChild(container);
      }
  };







  return null; // Componente de servicio invisible
};

'use client';

import React, { useState } from 'react';
import { useLanguage } from '@/lib/context/LanguageContext';
import { EtlPreset, EtlRecordType, EtlField, EtlRecordBehavior } from '@/lib/types/etl.types';
import { SamplePreview } from './SamplePreview';
import { CogIcon, EyeIcon, TrashIcon, ListIcon, XIcon, SaveIcon, UndoIcon, PlayIcon, FolderIcon } from '@/components/common/Icons';
import { useRouter } from 'next/navigation';

interface EtlDesignerProps {
  preset: EtlPreset;
  onUpdate: (updated: EtlPreset) => void;
  onSave: () => void;
}

export const EtlDesigner: React.FC<EtlDesignerProps> = ({ preset, onUpdate, onSave }) => {
  const { t } = useLanguage();
  const router = useRouter();
  const [activeRTIndex, setActiveRTIndex] = useState(0);
  const [undoStack, setUndoStack] = useState<string[]>([]);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [showRTModal, setShowRTModal] = useState(false);
  const [showSampleModal, setShowSampleModal] = useState(false);

  const activeRT = preset.recordTypes[activeRTIndex] || null;

  const handleLaunchExecutor = () => {
    onSave(); // Auto-save before jumping
    router.push(`/etl?view=executor&id=${preset.id}`);
  };

  const snapshot = () => {
    setUndoStack(prev => [...prev.slice(-19), JSON.stringify(preset)]);
  };

  const undo = () => {
    if (undoStack.length === 0) return;
    const last = undoStack[undoStack.length - 1];
    setUndoStack(prev => prev.slice(0, -1));
    onUpdate(JSON.parse(last));
  };

  const updatePreset = (patch: Partial<EtlPreset>) => {
    snapshot();
    onUpdate({ ...preset, ...patch, updatedAt: Date.now() });
  };

  const updateRT = (index: number, patch: Partial<EtlRecordType>) => {
    const newRTs = [...preset.recordTypes];
    newRTs[index] = { ...newRTs[index], ...patch };
    updatePreset({ recordTypes: newRTs });
  };

  const addRT = () => {
    const newRT: EtlRecordType = {
      name: `TIPO_${preset.recordTypes.length + 1}`,
      trigger: '',
      triggerStart: 0,
      behavior: 'DATA',
      range: '',
      fields: []
    };
    updatePreset({ recordTypes: [...preset.recordTypes, newRT] });
    setActiveRTIndex(preset.recordTypes.length);
  };

  const removeRecordType = () => {
    if (!activeRT) return;
    if (!confirm(t('common.confirm_delete').toUpperCase())) return;
    const newRTs = preset.recordTypes.filter((_, i) => i !== activeRTIndex);
    updatePreset({ recordTypes: newRTs });
    setActiveRTIndex(Math.max(0, activeRTIndex - 1));
