'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { useLanguage } from '@/lib/context/LanguageContext';
import { EtlPreset, EtlRecordType } from '@/lib/types/etl.types';

interface SamplePreviewProps {
  preset: EtlPreset;
  activeRecordTypeName?: string;
}

export const SamplePreview: React.FC<SamplePreviewProps> = ({ preset, activeRecordTypeName }) => {
  const { t } = useLanguage();
  const [lines, setLines] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const [encoding, setEncoding] = useState(preset.encoding || 'utf-8');

  useEffect(() => {
    setEncoding(preset.encoding || 'utf-8');
  }, [preset.encoding]);

  const loadFile = useCallback((file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      setLines(text.split(/\r?\n/).slice(0, 100)); // Load first 100 lines
    };
    reader.readAsText(file, encoding);
  }, [encoding]);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file) loadFile(file);
  };

  const matchesPattern = (input: string, pattern: string) => {
    if (input.length !== pattern.length) return false;
    for (let i = 0; i < pattern.length; i++) {
       if (pattern[i] === '?') continue;
       if (pattern[i] === '*') { if (input[i] !== ' ') return false; continue; }
       if (pattern[i] !== input[i]) return false;
    }
    return true;
  };

  const isLineInRange = (line: number, range: string) => {
    if (!range) return false;
    const parts = range.split(',');
    for (const part of parts) {
      if (part.includes('-')) {
        const [start, end] = part.split('-').map(Number);
        if (line >= start && line <= end) return true;
      } else {
        if (Number(part) === line) return true;
      }
    }
    return false;
  };

  const getLineMatch = (line: string, index: number) => {
    const totalLines = index + 1;
    const headerMatch = preset.recordTypes.find(r => r.behavior === 'HEADER' && isLineInRange(totalLines, r.range));
    if (headerMatch) return headerMatch;

    for (const rule of preset.recordTypes.filter(r => r.behavior === 'DATA')) {
      if (!rule.trigger) continue;
      const start = preset.recordTypeLen > 0 ? preset.recordTypeStart : rule.triggerStart;
      const len = preset.recordTypeLen > 0 ? preset.recordTypeLen : rule.trigger.length;
      if (line.length < start + len) continue;
      const cand = line.substring(start, start + len).trim();
      if (preset.recordTypeLen > 0) {
        if (matchesPattern(cand, rule.trigger)) return rule;
      } else {
        const spec = line.substring(rule.triggerStart, rule.triggerStart + rule.trigger.length);
        if (matchesPattern(spec, rule.trigger)) return rule;
      }
    }
    return null;
  };

  return (
    <div className="flex-col" style={{ height: '100%', gap: '12px' }}>
      <h3 className="station-form-section-title">PREVIEW_ENGINE</h3>

      <div 
        className="station-card"
        style={{ flex: 1, minHeight: 0, overflowY: 'auto', background: 'var(--bg-color)', borderStyle: isDragging ? 'dashed' : 'solid', borderColor: isDragging ? 'var(--primary-color)' : 'var(--border-color)' }}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={handleDrop}
      >
        {lines.length === 0 ? (
          <div style={{ height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', opacity: 0.3 }}>
            <p style={{ fontWeight: 800 }}>{t('processor.drop').toUpperCase()}</p>
            <small style={{ fontSize: '0.65rem' }}>MONO_STREAM_READY</small>
          </div>
        ) : (
          <div style={{ padding: '8px' }}>
            {lines.map((line, i) => {
              const match = getLineMatch(line, i);
              const isActive = match?.name === activeRecordTypeName;
              return (
                <div key={i} style={{ display: 'flex', gap: '12px', padding: '2px 0', alignItems: 'center', borderBottom: '1px solid rgba(var(--primary-color), 0.05)', background: isActive ? 'rgba(var(--primary-color), 0.1)' : 'transparent' }}>
                  <span style={{ width: '32px', opacity: 0.3, fontSize: '0.65rem', fontWeight: 600, textAlign: 'right' }}>{(i + 1).toString().padStart(3, '0')}</span>
                  <pre style={{ margin: 0, fontSize: '0.85rem', whiteSpace: 'pre', flex: 1, color: match ? 'var(--primary-color)' : 'var(--text-secondary)' }}>{line || ' '}</pre>
                  {match && (
                    <span className="station-badge station-badge-blue" style={{ fontSize: '0.6rem', padding: '0 4px', height: '16px' }}>
                      {match.name.substring(0, 10)}
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

'use client';

import React, { useState, useCallback } from 'react';
import { FolderIcon, ArrowUpIcon, ArrowDownIcon, XIcon, ShieldCheckIcon, LockIcon, UnlockIcon, TrashIcon } from '@/components/common/Icons';
import { useLanguage } from '@/lib/context/LanguageContext';
import styles from './FileProcessor.module.css';

interface SelectedFile {
  file: File;
  id: string;
}

interface FileProcessorProps {
  files: SelectedFile[];
  setFiles: React.Dispatch<React.SetStateAction<SelectedFile[]>>;
  onClear?: (count: number) => void;
  onSort?: (asc: boolean) => void;
  isProcessing: boolean;
  stats?: { success: number; error: number; skip: number };
  emptyIcon?: React.ReactNode;
  hideEmpty?: boolean;
}

const FileProcessor: React.FC<FileProcessorProps> = ({ 
  files,
  setFiles,
  onClear,
  onSort,
  isProcessing,
  stats = { success: 0, error: 0, skip: 0 },
  emptyIcon = <ShieldCheckIcon size={64} style={{ marginBottom: '16px' }} />,
  hideEmpty = false
}) => {
  const { t } = useLanguage();
  const [isDragging, setIsDragging] = useState(false);

  const addFiles = useCallback((newFiles: FileList | File[]) => {
    const fileList = Array.from(newFiles);
    setFiles(prev => {
      const uniqueNewFiles = fileList.filter(nf => 
        !prev.some(p => p.file.name === nf.name && p.file.size === nf.size)
      ).map(f => ({ file: f, id: Math.random().toString(36).substr(2, 9) }));

      return [...prev, ...uniqueNewFiles];
    });
  }, []);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      addFiles(e.dataTransfer.files);
    }
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  const clearFiles = () => {
    const count = files.length;
    setFiles([]);
    if (onClear && count > 0) onClear(count);
  };

  const sortFiles = (asc: boolean) => {
    setFiles(prev => {
      const sorted = [...prev].sort((a, b) => 
        asc ? a.file.name.localeCompare(b.file.name) : b.file.name.localeCompare(a.file.name)
      );
      return sorted;
    });
    if (onSort) onSort(asc);
  };

  return (
    <div className="flex-col" style={{ gap: '24px', height: '100%' }}>

      <div className="station-card" style={{ padding: '0', overflow: 'hidden' }}>
        <div 
          className={`station-dropzone ${isDragging ? 'active' : ''}`}
          style={{ margin: '16px' }}
          onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
          onDragLeave={() => setIsDragging(false)}
          onDrop={handleDrop}
        >
          <FolderIcon size={40} style={{ marginBottom: '8px', opacity: 0.4 }} />
          <p className="station-shimmer-text" style={{ fontSize: '0.85rem' }}>{t('processor.dropzone').toUpperCase()}</p>
          <input 
            type="file" 
            multiple 
            onChange={(e) => e.target.files && addFiles(e.target.files)}
          />
        </div>

        <header className="station-registry-header" style={{ cursor: 'default', display: 'flex', justifyContent: 'space-between' }}>
          <div className="flex-row" style={{ alignItems: 'baseline', gap: '16px' }}>
            <span className="station-registry-item-name">{t('processor.processing_queue', { n: files.length }).toUpperCase()}</span>
            <div className="station-tech-summary" style={{ border: 'none', marginTop: 0, paddingTop: 0, gap: '12px', opacity: 0.8 }}>
              <div className="station-tech-item"><span className="station-tech-label">OK:</span> <span className="txt-ok">{stats.success}</span></div>
              <div className="station-tech-item"><span className="station-tech-label">SKP:</span> <span className="txt-warn">{stats.skip}</span></div>
              <div className="station-tech-item"><span className="station-tech-label">ERR:</span> <span className="txt-err">{stats.error}</span></div>
            </div>
          </div>
          <div className="flex-row" style={{ gap: '8px' }}>
            <button onClick={() => sortFiles(true)} className="station-btn" style={{ padding: '4px' }} title={t('processor.sort_az').toUpperCase()}><ArrowUpIcon size={16} /></button>
            <button onClick={() => sortFiles(false)} className="station-btn" style={{ padding: '4px' }} title={t('processor.sort_za').toUpperCase()}><ArrowDownIcon size={16} /></button>
            <button onClick={clearFiles} className="station-btn" style={{ padding: '4px', color: 'var(--status-err)' }} title={t('processor.clear_list').toUpperCase()}><TrashIcon size={16} /></button>
          </div>
        </header>
        <div style={{ flex: 1, overflowY: 'auto' }}>
          {files.length === 0 ? (
            !hideEmpty && (
              <div className="station-empty-state">
                {emptyIcon}
                <span className="station-shimmer-text">{t('processor.waiting_files').toUpperCase()}</span>
              </div>
            )
          ) : (
            <div className="station-registry-list" style={{ padding: '8px' }}>
              {files.map(({ file, id }) => (
                <div key={id} className="station-registry-item" style={{ cursor: 'default' }}>
                  <div className="station-registry-item-left">
                    <div className="station-registry-item-icon">
                      <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: 'var(--primary-color)', opacity: 0.6 }} />
                    </div>
                    <div className="station-registry-item-info">
                      <span className="station-registry-item-name" style={{ fontSize: '0.85rem' }}>{file.name}</span>
                      <span className="station-registry-item-meta">{(file.size / 1024).toFixed(1)} KB • {file.type || 'RAW_DATA'}</span>
                    </div>
                  </div>
                  <button 
                    onClick={() => removeFile(id)} 
                    className="station-btn icon-only err"
                    style={{ background: 'transparent', border: 'none' }}
                  >
                    <XIcon size={14} />
                  </button>
                </div>
              ))}
            </div>

          )}
        </div>
      </div>

    </div>
  );
};

