/**
 * generateCanvasFingerprint (Normalized v2)
 * Procesa un canvas de renderizado para obtener su huella SHA-256 industrial.
 */
export async function generateCanvasFingerprint(
  canvas: HTMLCanvasElement,
  targetWidth: number = 512,
  targetHeight: number = 724
): Promise<string> {
  const tmp = document.createElement('canvas');
  tmp.width = targetWidth;
  tmp.height = targetHeight;

  const tctx = tmp.getContext('2d', { willReadFrequently: true })!;
  tctx.drawImage(canvas, 0, 0, targetWidth, targetHeight);

  const imgData = tctx.getImageData(0, 0, targetWidth, targetHeight);
  const grayBytes = new Uint8Array(targetWidth * targetHeight);

  for (let i = 0, j = 0; i < imgData.data.length; i += 4, j++) {
    const r = imgData.data[i];
    const g = imgData.data[i + 1];
    const b = imgData.data[i + 2];
    // Luminancia industrial (BT.601)
    grayBytes[j] = (r * 0.299 + g * 0.587 + b * 0.114) | 0;
  }

  const digest = await crypto.subtle.digest('SHA-256', grayBytes);
  return Array.from(new Uint8Array(digest))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

export async function verifyGoldenLayout(
  currentCanvas: HTMLCanvasElement, 
  goldenHash: string
): Promise<boolean> {
  const currentHash = await generateCanvasFingerprint(currentCanvas);
  return currentHash === goldenHash;
}

/**
 * Package Auditor Logic
 * Compliance: 02-code-quality-architecture (English logic)
 * Compliance: 04-compliance-security (Zero-Knowledge, Safe ZIP handling)
 * 
 * This module cross-references a GAWEB index with a ZIP archive.
 */

import JSZip from 'jszip';
import { GawebAuditResult } from './gaweb-auditor.logic';
import { md5 } from '../utils/crypto.utils';

export interface PackageAuditResult {
  zipFilesCount: number;
  missingFiles: string[];
  orphanedFiles: string[];
  md5Match?: boolean;
}

/**
 * Cross-references GAWEB records with ZIP archive entries.
 */
export async function auditPackageIntegrity(
  gaweb: GawebAuditResult, 
  zipBlob: Blob,
  md5Witness?: string
): Promise<PackageAuditResult> {
  const zip = new JSZip();
  const content = await zip.loadAsync(zipBlob);
  const zipFileNames = Object.keys(content.files);
  const normalizedZipNames = new Set(zipFileNames.map(n => n.toLowerCase()));

  const result: PackageAuditResult = {
    zipFilesCount: zipFileNames.length,
    missingFiles: [],
    orphanedFiles: [],
  };

  // 1. MD5 Witness Check (Optional)
  if (md5Witness) {
     const buffer = await zipBlob.arrayBuffer();
     const textContent = new TextDecoder().decode(new Uint8Array(buffer));
     const calculatedMd5 = md5(textContent); // Simplified for browser blobs
     result.md5Match = (calculatedMd5.toLowerCase() === md5Witness.trim().toLowerCase());
  }

  // 2. Cross-Integrity Check
  // Each record in GAWEB must have a corresponding PDF in the ZIP
  const gawebReferencedFiles = new Set<string>();

  gaweb.parsedData.forEach((record, index) => {
    const rawPdfName = record['PdfName'] || '';
    const cleanPdfName = rawPdfName.trim();

    if (cleanPdfName) {
      const targetFile = `${cleanPdfName}.pdf`.toLowerCase();
      gawebReferencedFiles.add(targetFile);

      if (!normalizedZipNames.has(targetFile)) {
        // Add to gaweb errors as well for UI visibility
        gaweb.errors.push({
          line: index + 1,
          field: 'PdfName',
          position: '212-251', // Modern position for PdfName
          severity: 'ERROR',
          messageKey: 'audit.errors.missing_pdf',
          value: cleanPdfName
        });
        result.missingFiles.push(cleanPdfName);
      }
    }
  });

  // 3. Orphan Check (Optional Warnings)
  // Check if there are PDFs in the ZIP that are not in the index
  zipFileNames.forEach(zipFile => {
    if (zipFile.toLowerCase().endsWith('.pdf') && !gawebReferencedFiles.has(zipFile.toLowerCase())) {
      result.orphanedFiles.push(zipFile);
      // Add a warning to the overall audit
      gaweb.warnings.push({
        line: 0,
        field: 'ZIP',
        position: 'N/A',
        severity: 'WARNING',
        messageKey: 'audit.errors.orphaned_pdf',
        value: zipFile
      });
    }
  });

  return result;
}

/**
 * CryptoService - Web Crypto Implementation of the ABDFN Encryption Standard.
 * 
 * Replicates the logic of ABDTools.Core.Crypto.CryptoService to ensure 
 * 100% compatibility with files encrypted via the original C# utility.
 */

const SALT_SIZE = 16;      // 128-bit
const NONCE_SIZE = 12;     // 96-bit (GCM standard)
const KEY_SIZE = 32;       // AES-256
const TAG_SIZE = 16;       // 128-bit (GCM standard)
const ITERATIONS = 100000; // PBKDF2 iterations (matching C#)

export interface ProcessingResult {
  success: boolean;
  fileName: string;
  error?: string;
  skipped?: boolean;
}

export class CryptoService {
  /**
   * Derives a 256-bit key from a password and salt using PBKDF2.
   */
  private static async deriveKey(password: string, salt: Uint8Array): Promise<CryptoKey> {
    const encoder = new TextEncoder();
    const passwordBytes = encoder.encode(password);

    // Import the raw password as a key for PBKDF2
    const baseKey = await crypto.subtle.importKey(
      'raw',
      passwordBytes,
      'PBKDF2',
      false,
      ['deriveBits', 'deriveKey']
    );

    // Derive the actual AES-GCM key
    return crypto.subtle.deriveKey(
      {
        name: 'PBKDF2',
        salt: salt as any, // Cast to any to avoid TypeScript type mismatch with SharedArrayBuffer on Vercel
        iterations: ITERATIONS,
        hash: 'SHA-256'
      },
      baseKey,
      { name: 'AES-GCM', length: KEY_SIZE * 8 },
      false, // Key is not extractable
      ['encrypt', 'decrypt']
    );
  }

  /**
   * Encrypts a file using AES-256-GCM.
   * Structure: [Salt(16)] + [Nonce(12)] + [Ciphertext] + [Tag(16)] 
   * NOTE: Web Crypto appends the tag to the ciphertext.
   */
  public static async encryptFile(file: File, password: string): Promise<Blob> {
    const fileBytes = new Uint8Array(await file.arrayBuffer());

    // 1. Generate random Salt and Nonce
    const salt = crypto.getRandomValues(new Uint8Array(SALT_SIZE));
    const nonce = crypto.getRandomValues(new Uint8Array(NONCE_SIZE));

    // 2. Derive Key
    const key = await this.deriveKey(password, salt);

    // 3. Encrypt
    // For GCM, the 'tag' is automatically appended to the ciphertext by encrypt()
    const encryptedContent = await crypto.subtle.encrypt(
      {
        name: 'AES-GCM',
        iv: nonce,
        tagLength: TAG_SIZE * 8
      },
      key,
      fileBytes
    );

    // 4. Assemble: [Salt][Nonce][Ciphertext+Tag]
    // Web Crypto's encryptedContent = [Ciphertext][Tag] (16 bytes at the end)
    // Actually, C# code wrote: [Salt][Nonce][Tag][Ciphertext]
    // We MUST match the C# order exactly: [Salt][Nonce][Tag][Ciphertext]

    const encryptedArray = new Uint8Array(encryptedContent);
    const tag = encryptedArray.slice(-TAG_SIZE);
    const ciphertextOnly = encryptedArray.slice(0, -TAG_SIZE);

    const finalResult = new Uint8Array(SALT_SIZE + NONCE_SIZE + TAG_SIZE + ciphertextOnly.length);
    finalResult.set(salt, 0);
    finalResult.set(nonce, SALT_SIZE);
    finalResult.set(tag, SALT_SIZE + NONCE_SIZE);
    finalResult.set(ciphertextOnly, SALT_SIZE + NONCE_SIZE + TAG_SIZE);

    return new Blob([finalResult], { type: 'application/octet-stream' });
  }

  /**
   * Decrypts a file using AES-256-GCM.
   */
  public static async decryptFile(file: File, password: string): Promise<Blob> {
    const data = new Uint8Array(await file.arrayBuffer());

    const minSize = SALT_SIZE + NONCE_SIZE + TAG_SIZE;
    if (data.length < minSize) {
      throw new Error('Archivo demasiado corto o formato incorrecto.');
    }

    // 1. Extract components (matching C# order: Salt, Nonce, Tag, Ciphertext)
    const salt = data.slice(0, SALT_SIZE);
    const nonce = data.slice(SALT_SIZE, SALT_SIZE + NONCE_SIZE);
    const tag = data.slice(SALT_SIZE + NONCE_SIZE, SALT_SIZE + NONCE_SIZE + TAG_SIZE);
    const ciphertext = data.slice(SALT_SIZE + NONCE_SIZE + TAG_SIZE);

    // 2. Derive Key
    const key = await this.deriveKey(password, salt);

    // 3. Web Crypto expects [Ciphertext][Tag] concatenated for decryption
    const combinedData = new Uint8Array(ciphertext.length + TAG_SIZE);
    combinedData.set(ciphertext, 0);
    combinedData.set(tag, ciphertext.length);

    // 4. Decrypt
    try {
      const decryptedBuffer = await crypto.subtle.decrypt(
        {
          name: 'AES-GCM',
          iv: nonce,
          tagLength: TAG_SIZE * 8
        },
        key,
        combinedData
      );

      return new Blob([decryptedBuffer], { type: 'application/octet-stream' });
    } catch (e) {
      throw new Error('Contraseña incorrecta o archivo dañado.');
    }
  }
}

import { db } from '../db/db';
import { SuiteDump, LetterTemplateDump } from '../types/dump.types';

/**
 * Industrial Utility for Full Database Export/Import (Era 6)
 * Handles binary DOCX content conversion to Base64 for JSON portability.
 */
export class DbSyncService {

  /**
   * Generates a single JSON Blob containing the entire application state.
   */
  static async exportSuite(): Promise<Blob> {
    const [presets, templates, mappings, goldenTests, auditHistory] = await Promise.all([
      db.presets_v6.toArray(),
      db.lettertemplates_v6.toArray(),
      db.lettermappings_v6.toArray(),
      db.golden_tests_v6.toArray(),
      db.audit_history_v6.toArray(),
    ]);

    // Handle Binary Content (DOCX)
    const templatesWithBase64: LetterTemplateDump[] = await Promise.all(
      templates.map(async (tpl) => {
        const { binaryContent, ...rest } = tpl;
        const dump: LetterTemplateDump = { ...rest };

        if (binaryContent) {
          dump.binaryBase64 = this.arrayBufferToBase64(binaryContent);
        }

        return dump;
      })
    );

    const dump: SuiteDump = {
      version: 'abdfn-suite-v6',
      generatedAt: new Date().toISOString(),
      presets: presets as any,
      templates: templatesWithBase64,
      mappings: mappings as any,
      goldenTests: goldenTests as any,
      auditHistory: auditHistory as any,
    };

    return new Blob([JSON.stringify(dump, null, 2)], { type: 'application/json' });
  }

  /**
   * Imports a SuiteDump JSON into the local IndexedDB.
   */
  static async importSuite(file: File, mode: 'REPLACE' | 'MERGE' = 'MERGE'): Promise<void> {
    const text = await file.text();
    const dump: SuiteDump = JSON.parse(text);

    if (dump.version !== 'abdfn-suite-v6') {
      throw new Error('VERSION_MISMATCH: Unsupported dump version');
    }

    // Transaction for industrial integrity
    await db.transaction('readwrite', [
      db.presets_v6, 
      db.lettertemplates_v6, 
      db.lettermappings_v6, 
      db.golden_tests_v6, 
      db.audit_history_v6
    ], async () => {

      if (mode === 'REPLACE') {
        await Promise.all([
          db.presets_v6.clear(),
          db.lettertemplates_v6.clear(),
          db.lettermappings_v6.clear(),
          db.golden_tests_v6.clear(),
          db.audit_history_v6.clear(),
        ]);
      }

      // 1. Presets
      for (const p of dump.presets) {
        await db.presets_v6.put(p); // put = update if exists, add if not
      }

      // 2. Templates (Recover binary DOCX)
      for (const t of dump.templates) {
        const { binaryBase64, ...rest } = t;
        const record: any = { ...rest };

        if (binaryBase64) {
          record.binaryContent = this.base64ToArrayBuffer(binaryBase64);
        }

        await db.lettertemplates_v6.put(record);
      }

      // 3. Mappings
      for (const m of dump.mappings) {
        await db.lettermappings_v6.put(m);
      }

      // 4. Goldens
      if (dump.goldenTests) {
        for (const g of dump.goldenTests) {
          await db.golden_tests_v6.put(g);
        }
      }

      // 5. History
      if (dump.auditHistory) {
        for (const h of dump.auditHistory) {
          await db.audit_history_v6.put(h);
        }
      }
    });

    console.log(`[ABDFN-SYNC] Import completed successfully. Mode: ${mode}`);
  }

  /**
   * Helper: ArrayBuffer -> Base64
   */
  private static arrayBufferToBase64(buffer: ArrayBuffer): string {
    let binary = '';
    const bytes = new Uint8Array(buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  }

  /**
   * Helper: Base64 -> ArrayBuffer
   */
  private static base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binary = atob(base64);
    const len = binary.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    return bytes.buffer;
  }
}

