const GawebUtility = {
  generateDocName: (baseHash: string, index: number) => {
    const idxStr = (index + 1).toString().padStart(7, '0');
    return `${baseHash.substring(0, 11)}${idxStr}`;
  },

  serializeDynamic: (fields: any[], data: any) => {
    let body = "";
    fields.forEach((field: any) => {
      let val = data[field.name] || "";
      if (field.isNumeric) {
        body += val.toString().replace(/\D/g, '').substring(0, field.length).padStart(field.length, '0');
      } else {
        body += val.toString().substring(0, field.length).padEnd(field.length, ' ');
      }
    });
    return body.padEnd(300, ' ');
  }
};

async function calculateSha256(data: any) {
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// --- MANEJADOR PRINCIPAL ---

self.onmessage = async (e: MessageEvent) => {
  const { dataFile, template, mapping, etlPreset, options, isStreaming = false, gawebFields = [] } = e.data;

  // Naming Canonizado (Smart Loader - Worker Side Backup)
  const codDocumento = options.codDocumento || (options as any).codDocto || 'X00000';

  self.postMessage({ type: 'HEARTBEAT' });

  try {
    if (typeof JSZip === 'undefined' || typeof Handlebars === 'undefined') {
        throw new Error('Librerías externas no cargadas. Ejecute SCRIPT/vendorize_libs.ps1');
    }

    const zipOutput = new JSZip();
    const gawebLines: string[] = [];
    const auditLines = ['INDICE;DOC_NAME;SHA256;TIMESTAMP'];

    let docxTemplate = null;
    if (template.type === 'DOCX' && template.binaryContent) {
      docxTemplate = template.binaryContent;
    }

    const dataStream = dataFile.stream().getReader();
    const decoder = new TextDecoder('windows-1252'); 

    let lineCount = 0;
    let processedCount = 0;
    let partialLine = '';

    const industrialBaseHash = (Math.random().toString(36).substring(2, 10) + Date.now().toString(36)).substring(0, 11);

    self.postMessage({ type: 'LOG', payload: { type: 'info', message: `INDUSTRIAL MOTOR (Era 5) iniciado.` } });

    while (true) {
      const { done, value } = await dataStream.read();
      if (done) break;

      const text = decoder.decode(value, { stream: true });
      const lines = (partialLine + text).split(/\r?\n/);
      partialLine = lines.pop() || '';

      for (const line of lines) {
        if (line.trim() === '') continue;
        lineCount++;
        if (lineCount === 1) continue; 

        let rt = null;
        let mergeData: Record<string, any> = {
          _INDEX: (lineCount - 1).toString(),
          _LOTE: options.lote,
          _OFICINA: options.oficina,
          _FECHA_CARTA: options.fechaCarta,
          _COD_DOCUMENTO: codDocumento
        };

        for (const type of etlPreset.recordTypes) {
           const trigger = type.trigger;
           const start = type.triggerStart || 0;
           if (line.substring(start, start + trigger.length).trim() === trigger.trim()) {
             rt = type;
             break;
           }
        }

        if (rt) {
          mapping.mappings.forEach((m: any) => {
            const field = rt.fields.find((f: any) => 
               (f.name || f.Name) === m.sourceField || f.id === m.sourceField
            );

            if (field) {
               const s = field.start ?? field.Start;
               const l = field.length ?? field.Length;
               const idx = field.index ?? field.Index;

               const val = (typeof s === 'number' && typeof l === 'number')
                  ? line.substring(s, s + l)
                  : line.split(';')[idx] || '';

               mergeData[m.templateVar] = val.trim();
            }
          });

          if (rt.name === 'DATA') {
             processedCount++;
             const docName = GawebUtility.generateDocName(industrialBaseHash, processedCount - 1);
             const fileName = `${docName}.${template.type === 'DOCX' ? 'docx' : 'html'}`;
             let content;

             try {
                if (template.type === 'DOCX' && docxTemplate) {
                  const zip = new (self as any).PizZip(docxTemplate);
                  const doc = new (self as any).docxtemplater(zip, { paragraphLoop: true, linebreaks: true });
                  doc.render(mergeData);
                  content = doc.getZip().generate({ type: 'arraybuffer' });
                } else {
                  // UPGRADE: Handlebars Compiler para HTML
                  const hbsTemplate = Handlebars.compile(template.content || '');
                  const merged = hbsTemplate(mergeData);
                  content = new TextEncoder().encode(merged).buffer;
                }

                const sha256 = await calculateSha256(content);
                auditLines.push(`${lineCount - 1};${fileName};${sha256};${new Date().toISOString()}`);

                if (isStreaming) {
                  self.postMessage({ 
                    type: 'DOCUMENT_READY', 
                    payload: { 
                      name: fileName, 
                      content, 
                      index: processedCount,
                      isFirst: processedCount === 1 
                    } 
                  });
                } else {
                  zipOutput.file(fileName, content);
                }

                // SERIALIZACIÓN GAWEB (Protocolo Unificado v4)
                const cfg = etlPreset.gawebConfig || {};
                const indexData = {
                   LetterType: ' ',
                   Format: codDocumento === 'x00054' ? '04' : (cfg.formatoCarta || '04'),
                   GenerationDate: options.fechaGeneracion || cfg.fechaGeneracion || options.fechaCarta,
                   Batch: options.lote || '0000',
                   Sequential: (lineCount - 1).toString(),
                   Page: cfg.paginasDefecto ? cfg.paginasDefecto.toString() : '0001',
                   DocCode: codDocumento.substring(0, 6),
                   Version: '0000',
                   ContractClass: '00',
                   ContractCode: mergeData.CodContrato || mergeData._INDEX,
                   CLALF: mergeData.CLALF || '',
                   ForceSend: cfg.forzarMetodo || ' ',
                   Language: cfg.idioma || '  ',
                   SavingOpCode: cfg.savingsOpCode || '',
                   SavingOpAccount: cfg.savingsOpAccount || '',
                   SavingOpSign: cfg.savingsOpSign || '+',
                   SavingOpAmount: cfg.savingsOpAmount || '0',
                   SavingOpCurrency: cfg.savingsOpCurrency || '  ',
                   SavingOpISO: cfg.savingsOpISO || '   ',
                   SavingOpConcept: cfg.savingsOpConcept || '  ',
                   LetterDate: options.fechaCarta || cfg.fechaCarta || '',
                   DestinationIndicator: cfg.indicadorDestino || '0',
                   LoadDetail: '0000',
                   DeliveryWay: cfg.viaReparto || '',
                   PaperCopy: cfg.copiaPapel || '',
                   OfficeCode: options.oficina || cfg.oficina || '00000',
                   PdfName: docName
                };

                const gawebLine = GawebUtility.serializeDynamic(gawebFields, indexData);
                gawebLines.push(gawebLine);

                if (processedCount % 100 === 0) {
                   self.postMessage({ type: 'LOG', payload: { type: 'info', message: `PROGRESO: [${processedCount}] generados...` } });
                }
             } catch (renderErr) {
               self.postMessage({ type: 'LOG', payload: { type: 'error', message: `RENDER ERROR (L ${lineCount}): ${(renderErr as any).message}` } });
             }
          }
        }
      }
    }

    if (isStreaming && processedCount > 0) {
       const gawebContent = new TextEncoder().encode(gawebLines.join('\r\n')).buffer;
       self.postMessage({ type: 'DOCUMENT_READY', payload: { name: 'GAWEB.txt', content: gawebContent } });

       const auditContent = new TextEncoder().encode(auditLines.join('\r\n')).buffer;
       self.postMessage({ type: 'DOCUMENT_READY', payload: { name: 'AUDIT_REPORT.CSV', content: auditContent } });
    }

    if (isStreaming) {
       self.postMessage({ type: 'COMPLETE', payload: { count: processedCount } });
    } else {
       zipOutput.file('GAWEB.txt', gawebLines.join('\r\n'));
       zipOutput.file('AUDIT_REPORT.CSV', auditLines.join('\r\n'));
       const blob = await zipOutput.generateAsync({ type: 'blob' });
       self.postMessage({ type: 'COMPLETE', payload: { blob, name: `LOTE_${options.lote || '0000'}.zip`, count: processedCount } });
    }

  } catch (err) {
    self.postMessage({ type: 'LOG', payload: { type: 'error', message: `ERROR CRÍTICO: ${(err as any).message}` } });
  }
};

/**
 * ETL Processor Worker - ABDFN Aseptic Engine
 * Translates legacy C# ProcessorService logic to pure TypeScript.
 * Mandato 100% Inglés - Aseptic Standard ERA 5.
 */

import { EtlPreset, EtlRecordType, EtlField } from '../types/etl.types';
import { EtlProcessorOptions } from '../types/etl-processor.types';

// Wildcard matching logic from C#
const matchesPattern = (input: string, pattern: string): boolean => {
  if (input.length !== pattern.length) return false;

  for (let i = 0; i < pattern.length; i++) {
    const p = pattern[i];
    const c = input[i];

    if (p === '?') continue; // Match Any
    if (p === '*') {
      // Legacy C# Rule: * matches Space specifically
      if (c !== ' ') return false;
      continue;
    }
    if (p !== c) return false;
  }
  return true;
};

// Line range parsing from C# (e.g. "1-10,15")
const isLineInRange = (line: number, range: string): boolean => {
  if (!range || range.trim() === '') return false;

  const parts = range.split(',');
  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed.includes('-')) {
      const [start, end] = trimmed.split('-').map(s => parseInt(s, 10));
      if (!isNaN(start) && !isNaN(end) && line >= start && line <= end) return true;
    } else {
      const val = parseInt(trimmed, 10);
      if (!isNaN(val) && line === val) return true;
    }
  }
  return false;
};

// Identify Record Type based on triggers and ranges
const identifyRecordType = (line: string, lineNum: number, preset: EtlPreset): EtlRecordType | null => {
  // 1. Check Header/Footer ranges first
  const headerRules = preset.recordTypes.filter(r => r.behavior === 'HEADER');
  const hMatch = headerRules.find(r => isLineInRange(lineNum, r.range));
  if (hMatch) return hMatch;

  const footerRules = preset.recordTypes.filter(r => r.behavior === 'FOOTER');
  const fMatch = footerRules.find(r => isLineInRange(lineNum, r.range));
  if (fMatch) return fMatch;

  // 2. Data Matching logic
  const dataRules = preset.recordTypes.filter(r => r.behavior === 'DATA');
  let fallback: EtlRecordType | null = null;

  for (const rule of dataRules) {
    if (!rule.trigger || rule.trigger === '') {
      fallback = fallback || rule;
      continue;
    }

    if (line.length < rule.triggerStart + rule.trigger.length) continue;
    const candidate = line.substring(rule.triggerStart, rule.triggerStart + rule.trigger.length);

    if (matchesPattern(candidate, rule.trigger)) return rule;
  }

  return fallback;
};

// Field parsing logic
const parseLine = (line: string, fields: EtlField[]): Record<string, string> => {
  const result: Record<string, string> = {};
  for (const field of fields) {
    let val = '';
    if (field.start < line.length) {
      const length = Math.min(field.length, line.length - field.start);
      val = line.substring(field.start, field.start + length).trim();
    }
    result[field.name] = val;
  }
  return result;
};

// Main Processing Loop
self.onmessage = async (e) => {
  const { file, preset, options }: { file: File, preset: EtlPreset, options: EtlProcessorOptions } = e.data;

  try {
    const reader = file.stream().getReader();
    const decoder = new TextDecoder(options.encoding);
    let lineCount = 0;
    let partialLine = '';
    let isCancelled = false;

    self.postMessage({ type: 'LOG', payload: { type: 'info', message: `Starting process: ${file.name}` } });

    while (true) {
      const { done, value } = await reader.read();
      if (done || isCancelled) break;

      const text = decoder.decode(value, { stream: true });
      const lines = (partialLine + text).split(/\r?\n/);
      partialLine = lines.pop() || '';

      for (const line of lines) {
        lineCount++;

        // Skip logic (StartRow / EndRow)
        if (lineCount < options.startRow) continue;
        if (options.endRow > 0 && lineCount > options.endRow) {
          isCancelled = true;
          break;
        }

        const rt = identifyRecordType(line, lineCount, preset);
        if (rt) {
          const data = parseLine(line, rt.fields);

          // Send record back for writing
          self.postMessage({ 
            type: 'RECORD', 
            payload: { 
              typeName: rt.name, 
              data, 
              presetName: preset.name,
              headers: rt.fields.sort((a,b) => a.start - b.start).map(f => f.name)
            } 
          });
        }

        if (lineCount % 1000 === 0) {
          self.postMessage({ type: 'PROGRESS', payload: { processedLines: lineCount } });
        }
      }
    }

    self.postMessage({ type: 'LOG', payload: { type: 'success', message: `Process finished. Total lines: ${lineCount}` } });
    self.postMessage({ type: 'COMPLETE' });

  } catch (err: any) {
    self.postMessage({ type: 'LOG', payload: { type: 'error', message: `FATAL ERROR: ${err.message}` } });
  }
};

/// <reference lib="webworker" />

import { auditGawebLine } from '../logic/gaweb-auditor.logic';
import { auditPackageIntegrity } from '../logic/package-auditor.logic';
import type {
  AuditWorkerInMessage,
  AuditWorkerOutMessage,
  GawebSummary,
  GawebRow,
  GawebErrorLite,
} from '../types/audit-worker.types';

declare const self: DedicatedWorkerGlobalScope;

let state: {
  isRunning: boolean;
  totalLines: number;
  totalErrors: number;
  totalWarnings: number;
  errorsByType: Record<string, number>;
  // Buffers de previsualización (Escala Industrial)
  dataPreview: GawebRow[];
  errorsPreview: GawebErrorLite[];
  maxErrorsPreview: number;
  encoding: 'windows-1252' | 'utf-8';
} = resetState();

function resetState() {
  return {
    isRunning: false,
    totalLines: 0,
    totalErrors: 0,
    totalWarnings: 0,
    errorsByType: {},
    dataPreview: [],
    errorsPreview: [],
    maxErrorsPreview: 500,
    encoding: 'windows-1252',
  };
}

function post(msg: AuditWorkerOutMessage) {
  self.postMessage(msg);
}

self.onmessage = async (event: MessageEvent<AuditWorkerInMessage>) => {
  const { type, payload } = event.data;

  if (type === 'START_AUDIT') {
    if (state.isRunning) {
        state.isRunning = false; // Cancel existing
    }

    state = resetState();
    state.isRunning = true;
    if (payload.encoding) state.encoding = payload.encoding;
    if (payload.maxErrorsPreview) state.maxErrorsPreview = payload.maxErrorsPreview;

    try {
      post({ type: 'HEARTBEAT' });
      await runGawebAuditStreaming(payload.gawebFile, payload.zipFile, payload.md5Witness);

      const summary: GawebSummary = {
        totalLines: state.totalLines,
        totalErrors: state.totalErrors,
        totalWarnings: state.totalWarnings,
        errorsByType: state.errorsByType
      };
      post({ type: 'SUMMARY_READY', payload: summary });
      post({ type: 'COMPLETE' });
    } catch (err: any) {
      post({ type: 'FATAL_ERROR', payload: { message: err?.message || 'Unknown Audit Error' } });
    } finally {
      state.isRunning = false;
    }
  }

  if (type === 'REQUEST_DATA_WINDOW') {
    const { start, end } = payload;
    const rows = state.dataPreview.filter(r => r.line >= start && r.line <= end);
    post({ type: 'DATA_WINDOW', payload: { start, end, rows } });
  }

  if (type === 'REQUEST_ERRORS_WINDOW') {
    const { start, end } = payload;
    const errors = state.errorsPreview.slice(start, end + 1);
    post({ type: 'ERRORS_WINDOW', payload: { start, end, errors } });
  }

  if (type === 'CANCEL_AUDIT') {
    state.isRunning = false;
  }
};

async function runGawebAuditStreaming(gawebFile: File, zipFile?: File, md5Witness?: string) {
  const reader = (gawebFile as any).stream().getReader();
  const decoder = new TextDecoder(state.encoding);

  let partialLine = '';
  let processedSinceLastProgress = 0;

  while (state.isRunning) {
    const { done, value } = await reader.read();
    if (done) break;

    const chunkText = decoder.decode(value, { stream: true });
    const text = partialLine + chunkText;
    const lines = text.split(/\r?\n/);
    partialLine = lines.pop() ?? '';

    for (const line of lines) {
      if (!state.isRunning) break;
      processSingleLine(line);
      processedSinceLastProgress++;

      if (processedSinceLastProgress >= 1000) {
        post({
          type: 'PROGRESS',
          payload: {
            processedLines: state.totalLines,
            errorsSoFar: state.totalErrors,
            warningsSoFar: state.totalWarnings
          }
        });
        processedSinceLastProgress = 0;
      }
    }
  }

  if (state.isRunning && partialLine.trim() !== '') {
    processSingleLine(partialLine);
  }

  if (zipFile && state.isRunning) {
    // Generamos un resultado parcial para la integridad del paquete
    const gawebResultPreview = {
      parsedData: state.dataPreview.map(r => r.fields),
      errors: state.errorsPreview.map(e => ({
        line: e.line,
        field: e.field,
        position: e.position,
        severity: e.severity,
        messageKey: e.messageKey,
        value: e.value
      }))
    };

    const pkg = await auditPackageIntegrity(gawebResultPreview as any, zipFile, md5Witness);
    post({ type: 'PACKAGE_RESULT', payload: pkg });
  }
}

function processSingleLine(rawLine: string) {
  const lineNo = state.totalLines + 1;
  const { record, errors, warnings } = auditGawebLine(rawLine, lineNo);

  state.totalLines++;

  const allAnomalies = [...errors, ...warnings];
  for (const exp of allAnomalies) {
    if (exp.severity === 'ERROR') state.totalErrors++;
    if (exp.severity === 'WARNING') state.totalWarnings++;

    const key = exp.messageKey;
    state.errorsByType[key] = (state.errorsByType[key] || 0) + 1;
  }

  // Guardamos en el buffer de previsualización (limitado para no saturar RAM)
  if (state.dataPreview.length < 10000) {
    state.dataPreview.push({ line: lineNo, fields: record });
  }

  for (const exp of allAnomalies) {
    if (state.errorsPreview.length >= state.maxErrorsPreview) break;
    state.errorsPreview.push({
      index: state.errorsPreview.length,
      line: exp.line,
      field: exp.field,
      position: exp.position,
      severity: exp.severity as any,
      messageKey: exp.messageKey,
      value: exp.value
    });
  }
}

