}

.station-checkbox:checked::after {
  content: "X";
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: var(--bg-color);
  font-weight: 900;
  font-size: 1rem;
}

.station-meter-container {
  width: 100%;
  height: 6px;
  background: var(--bg-color);
  border: 1px solid var(--border-color);
  overflow: hidden;
  margin-top: 8px;
}

.station-meter-bar {
  height: 100%;
  transition: width 0.4s var(--snap), background-color 0.4s var(--snap);
}

/* --- FILE PROCESSING & DROPZONES --- */
.station-dropzone {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 140px;
  border: 2px dashed var(--border-color);
  background: transparent;
  cursor: pointer;
  transition: all var(--snap);
  position: relative;
  text-align: center;
}

.station-dropzone:hover,
.station-dropzone.active {
  background: var(--bg-color);
  border-color: var(--primary-color);
  border-style: solid;
}

.station-dropzone input[type="file"] {
  position: absolute;
  inset: 0;
  opacity: 0;
  cursor: pointer;
}

.station-file-list {
  display: flex;
  flex-direction: column;
  background: var(--bg-color);
  border: 1px solid var(--border-color);
  overflow: hidden;
}

.station-file-item {
  display: flex;
  align-items: center;
  gap: 16px;
  padding: 12px 24px;
  border-bottom: 1px solid var(--border-color);
  transition: background var(--snap);
}

.station-file-item:last-child {
  border-bottom: none;
}

.station-file-item:hover {
  background: var(--surface-color);
}

/* --- CONSOLE & LOGGING SYSTEMS --- */
.station-console {
  display: flex;
  flex-direction: column;
  background: var(--bg-color);
  border: var(--border-thick) solid var(--border-color);
  overflow: hidden;
  position: relative;
}

.station-console-header {
  padding: 12px 16px;
  background: var(--surface-color);
  border-bottom: 1px solid var(--border-color);
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.station-console-area {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  font-family: var(--font-mono);
  font-size: 0.85rem;
  line-height: 1.5;
  background: var(--bg-color);
  position: relative;
}

/* Retro Scanline Effect */
.station-console-area::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: repeating-linear-gradient(
    rgba(18, 16, 16, 0) 0,
    rgba(18, 16, 16, 0.03) 50%,
    rgba(18, 16, 16, 0) 100%
  );
  background-size: 100% 4px;
  pointer-events: none;
  z-index: 10;
}

.station-console-log {
  display: flex;
  gap: 16px;
  margin-bottom: 6px;
}

.station-console-time {
  opacity: 0.4;
  font-size: 0.8em;
  min-width: 80px;
}

.station-console-status {
  font-weight: 900;
  min-width: 70px;
}

/* --- MODAL SYSTEM --- */
.station-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.85);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 5000;
  backdrop-filter: blur(4px);
  padding: 20px;
}

.station-modal {
  background: var(--bg-color);
  border: var(--border-thick) solid var(--border-color);
  box-shadow: 15px 15px 0px rgba(0, 0, 0, 0.5);
  width: 100%;
  max-width: 800px;
  max-height: 90vh;
  display: flex;
  flex-direction: column;
  animation: modalIn 0.3s var(--snap);
}

@keyframes modalIn {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

.station-modal-header {
  padding: 16px 24px;
  background: var(--surface-color);
  border-bottom: 2px solid var(--border-color);
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.station-modal-content {
  flex: 1;
  overflow-y: auto;
  padding: 32px;
}

.station-modal-footer {
  padding: 16px 24px;
  background: var(--surface-color);
  border-top: 1px solid var(--border-color);
  display: flex;
  justify-content: flex-end;
  gap: 16px;
}

/* --- STATION INTEGRITY BADGES (Era 5) --- */
.station-integrity-badge {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 6px 14px;
  background: rgba(var(--primary-color-rgb, 56, 189, 248), 0.05);
  border: 1px solid rgba(var(--primary-color-rgb, 56, 189, 248), 0.1);
  border-radius: 4px;
  font-family: var(--font-mono);
  font-size: 0.65rem;
  letter-spacing: 0.15rem;
  color: var(--primary-color);
  opacity: 0.8;
  pointer-events: none;
  animation: station-heartbeat 4s cubic-bezier(0.4, 0, 0.6, 1) infinite;
  text-transform: uppercase;
  font-weight: 800;
  box-shadow: 0 0 20px rgba(0,0,0,0.2);
}

.integrity-dot {
  width: 8px;
  height: 8px;
  background: var(--primary-color);
  border-radius: 50%;
  box-shadow: 0 0 10px var(--primary-color);
  animation: dot-pulse 2s infinite;
}

@keyframes station-heartbeat {
  0%, 100% { opacity: 0.4; transform: scale(1); filter: brightness(1); }
  50% { opacity: 1; transform: scale(1.02); filter: brightness(1.2); }
}

@keyframes dot-pulse {
  0% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.5); opacity: 0.5; }
  100% { transform: scale(1); opacity: 1; }
}

/* --- INDUSTRIAL BADGES --- */
.station-badge {
  display: inline-flex;
  align-items: center;
  padding: 2px 8px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  color: var(--text-secondary);
  font-size: 9px;
  font-weight: 900;
  border-radius: 2px;
  text-transform: uppercase;
  letter-spacing: 0.05rem;
}

.station-badge.success {
  background: rgba(34, 197, 94, 0.1);
  border-color: rgba(34, 197, 94, 0.3);
  color: #4ade80;
}

.station-badge.warning {
  background: rgba(245, 158, 11, 0.1);
  border-color: rgba(245, 158, 11, 0.3);
  color: #fbbf24;
}

.station-badge.error {
  background: rgba(239, 68, 68, 0.1);
  border-color: rgba(239, 68, 68, 0.3);
  color: #f87171;
}

.shell-container {
  display: grid;
  grid-template-areas: 
    "sidebar topbar"
    "sidebar content"
    "sidebar status";
  grid-template-columns: auto 1fr;
  grid-template-rows: 64px 1fr 32px;
  height: 100vh;
  width: 100vw;
  background: var(--bg-color);
}

.shell-sidebar {
  grid-area: sidebar;
  width: 280px;
  background: var(--surface-color);
  border-right: 1px solid var(--border-color);
  display: flex;
  flex-direction: column;
  transition: width var(--snap);
  z-index: 1000;
}

.shell-sidebar.collapsed {
  width: 80px;
}

.shell-topbar {
  grid-area: topbar;
  background: var(--header-bg);
  border-bottom: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 24px;
}

.shell-content {
  grid-area: content;
  overflow-y: auto;
  padding: var(--panel-padding);
  background: var(--bg-color);
}

.shell-status {
  grid-area: status;
  background: var(--surface-color);
  border-top: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  padding: 0 16px;
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05rem;
}

/* --- SCROLLBAR SYSTEM (Universal) --- */
::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 20px;
  border: 3px solid transparent;
  background-clip: content-box;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--text-secondary);
  border: 3px solid transparent;
  background-clip: content-box;
}

* {
  scrollbar-width: thin;
  scrollbar-color: var(--border-color) transparent;
}

:root {
  /* Common Design Tokens (Uncodixy Standard) */
  --font-mono: 'Space Mono', 'Roboto Mono', monospace;
  --panel-padding: 30px;
  --border-thick: 1px;
  --border-thin: 1px;
  --radius-std: 8px;
  --shadow-std: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  --snap: 0.1s ease;
}

/* DARK: Slate Noir */
[data-theme='dark'] {
  --bg-color: #0f172a;
  --surface-color: #1e293b;
  --border-color: #334155;
  --primary-color: #38bdf8;
  --secondary-color: #818cf8;
  --text-primary: #f8fafc;
  --text-secondary: #94a3b8;
  --accent-color: #f43f5e;
  --status-ok: #10b981;
  --status-warn: #f59e0b;
  --status-err: #ef4444;
  --header-bg: #1e293b;
  --header-text: #f8fafc;
  --input-bg: #0f172a;
}

/* LIGHT: Cloud Canvas */
[data-theme='light'] {
  --bg-color: #fafafa;
  --surface-color: #ffffff;
  --border-color: #e2e8f0;
  --primary-color: #2563eb;
  --secondary-color: #7c3aed;
  --text-primary: #0f172a;
  --text-secondary: #64748b;
  --accent-color: #d33;
  --status-ok: #059669;
  --status-warn: #d97706;
  --status-err: #dc2626;
  --header-bg: #ffffff;
  --header-text: #0f172a;
  --input-bg: #ffffff;
}

/* MIDNIGHT: Industrial High-Contrast */
[data-theme='midnight'] {
  --bg-color: #000000;
  --surface-color: #0c0c0c;
  --border-color: #1a1a1a;
  --primary-color: #ff9d00;   /* Amber industrial */
  --secondary-color: #00ff00; /* Phosphor Green */
  --text-primary: #e0e0e0;
  --text-secondary: #888888;
  --accent-color: #ff3e00;
  --status-ok: #00ff41;    /* Matrix Green */
  --status-warn: #ffcc00;
  --status-err: #ff0000;
  --header-bg: #050505;
  --header-text: #ff9d00;
  --input-bg: #000000;
}

/* --- EMPTY STATE & SHIMMER SYSTEM --- */
.station-empty-state {
  height: 100%;
  min-height: 180px;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0.6;
  font-weight: 700;
  text-transform: uppercase;
  padding: 80px 0;
  text-align: center;
}

.station-shimmer-text {
  background: linear-gradient(
    90deg,
    rgba(255, 255, 255, 0) 0%,
    rgba(255, 255, 255, 0.4) 50%,
    rgba(255, 255, 255, 0) 100%
  );
  background-size: 200% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  animation: shimmerTerm 3s infinite linear;
  letter-spacing: 0.1rem;
}

@keyframes shimmerTerm {
  from { background-position: 200% 0; }
  to { background-position: -200% 0; }
}

/* --- MISC UTILITIES --- */
.station-card {
  background: var(--surface-color);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-std);
  padding: 24px;
}

.flex-col { display: flex; flex-direction: column; }
.flex-row { display: flex; flex-direction: row; align-items: center; }
.flex-center { display: flex; align-items: center; justify-content: center; }
.flex-between { display: flex; align-items: center; justify-content: space-between; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }

/* --- BADGES --- */
.station-badge {
  display: inline-flex;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 0.6rem;
  font-weight: 900;
  text-transform: uppercase;
  border: 1px solid currentColor;
}

.station-badge-blue { color: #38bdf8; background: rgba(56, 189, 248, 0.1); }
.station-badge-green { color: #10b981; background: rgba(16, 185, 129, 0.1); }
.station-badge-orange { color: #f59e0b; background: rgba(245, 158, 11, 0.1); }
